class Solution:
    def wiggleSort(self, nums: List[int]) -> None:
        n = len(nums)
        arr = sorted(nums)
        mid = (n - 1) // 2
        j = mid
        for i in range(1, n, 2):
            nums[i] = arr[j]; j -= 1
        j = mid
        for i in range(0, n, 2):
            nums[i] = arr[j]; j -= 1

