void wiggleSort(int* nums, int n) {
    int* tmp = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) tmp[i] = nums[i];
    for (int i = 0; i < n-1; i++)
        for (int j = i+1; j < n; j++)
            if (tmp[j] < tmp[i]) { int t=tmp[i]; tmp[i]=tmp[j]; tmp[j]=t; }
    int mid = (n-1)/2, j = mid;
    for (int i = 1; i < n; i += 2) nums[i] = tmp[j--];
    j = mid;
    for (int i = 0; i < n; i += 2) nums[i] = tmp[j--];
    free(tmp);
}
